import React from 'react';
import Layout from '../components/4_unity/Layout';
import Header from '../components/3_organism/Header';
import FooterSection from '../components/3_organism/FooterSection';
import AboutHeroSection from '../components/3_organism/AboutHeroSection';
import AboutSplitSection from '../components/3_organism/AboutSplitSection';
import AboutStepsSection from '../components/3_organism/AboutStepsSection';
import AboutCardsSection from '../components/3_organism/AboutCardsSection';
import AboutComparisonSection from '../components/3_organism/AboutComparisonSection';
import AboutRoadmapSection from '../components/3_organism/AboutRoadmapSection';
import AboutFinalCtaSection from '../components/3_organism/AboutFinalCtaSection';
import {
  aboutHeroCards,
  aboutMechanicsCards,
  aboutLearningCards,
  aboutFuturePoints,
  aboutSections,
} from '../data/aboutInsureKidsPageData';
import './AboutInsureKidsPage.css';

function AboutInsureKidsPage() {
  return (
    <Layout>
      <Header />
      <main className="about-page">
        <div className="about-page__screen about-page__screen--hero">
          <AboutHeroSection {...aboutSections.hero} cards={aboutHeroCards} />
        </div>

        <div className="about-page__screen about-page__screen--balanced">
          <AboutSplitSection {...aboutSections.problem} />
        </div>

        <div className="about-page__screen about-page__screen--balanced">
          <AboutSplitSection {...aboutSections.solution} reverse />
        </div>

        <div className="about-page__screen about-page__screen--steps">
          <AboutStepsSection {...aboutSections.howItWorks} />
        </div>

        <div className="about-page__screen about-page__screen--cards">
          <AboutCardsSection {...aboutSections.mechanics} cards={aboutMechanicsCards} note={aboutSections.mechanics.note} />
        </div>

        <div className="about-page__screen about-page__screen--cards">
          <AboutCardsSection
            {...aboutSections.educationalValue}
            cards={aboutLearningCards}
            compact
            note={aboutSections.educationalValue.highlight}
          />
        </div>

        <div className="about-page__screen about-page__screen--balanced">
          <AboutSplitSection {...aboutSections.blog} reverse />
        </div>

        <div className="about-page__screen about-page__screen--balanced">
          <AboutComparisonSection {...aboutSections.whyItWorks} comparison={aboutSections.whyItWorks.comparison} />
        </div>

        <div className="about-page__screen about-page__screen--balanced">
          <AboutRoadmapSection {...aboutSections.future} points={aboutFuturePoints} />
        </div>

        <div className="about-page__screen about-page__screen--cta">
          <AboutFinalCtaSection {...aboutSections.finalCta} />
        </div>
      </main>
      <FooterSection />
    </Layout>
  );
}

export default AboutInsureKidsPage;
